// @ts-check
import { defineConfig } from 'astro/config';
import react from '@astrojs/react';
import tailwindcss from '@tailwindcss/vite';
import sitemap from '@astrojs/sitemap';

export default defineConfig({
  site: 'https://ainomi.co.jp',
  integrations: [react(), sitemap()],
  vite: {
    plugins: [tailwindcss()]
  }
});

// Site configuration
export const SITE_CONFIG = {
  name: "合同会社あいのみ",
  url: import.meta.env.PUBLIC_SITE_URL || "https://ainomi.co.jp",
  description: "仕事と介護の両立を支援する産業ケアマネージャー。介護離職防止のための企業向けサービスを提供しています。",
  locale: "ja_JP",
} as const;

// LINE configuration
export const LINE_CONFIG = {
  url: import.meta.env.PUBLIC_LINE_URL || "https://line.me/R/ti/p/@xxxxx",
  qrCodePath: "/images/line-qr.png",
} as const;

// Navigation items
export interface NavItem {
  label: string;
  href: string;
  children?: NavItem[];
}

export const NAV_ITEMS: NavItem[] = [
  { label: "ホーム", href: "/" },
  {
    label: "サービス",
    href: "/services",
    children: [
      { label: "産業ケアマネ", href: "/services/industrial-care" },
      { label: "ケアマネジメント", href: "/services/care-management" },
      { label: "研修・講演", href: "/services/training" },
    ],
  },
  { label: "会社概要", href: "/about" },
  { label: "お問い合わせ", href: "/contact" },
];

// Service cards for home page
export const SERVICE_CARDS = [
  {
    id: "industrial-care",
    icon: "Briefcase",
    image: "/images/service-industrial.jpg",
    title: "産業ケアマネ",
    description: "企業の介護離職防止を支援。従業員と企業の両方をサポートします。",
    href: "/services/industrial-care",
  },
  {
    id: "care-management",
    icon: "Heart",
    image: "/images/service-care.jpg",
    title: "ケアマネジメント",
    description: "東京・神奈川・埼玉・千葉でケアプラン作成からサービス調整まで。",
    href: "/services/care-management",
  },
  {
    id: "training",
    icon: "GraduationCap",
    image: "/images/service-training.jpg",
    title: "研修・講演",
    description: "介護離職防止セミナーや管理職向け研修を企業に提供します。",
    href: "/services/training",
  },
] as const;

// Company information
export const COMPANY_INFO = {
  name: "合同会社あいのみ",
  address: "東京都", // TODO: Update with actual address
  founded: "2024年",
  representative: "", // TODO: Update with actual name
  business: [
    "産業ケアマネージャー事業",
    "居宅介護支援事業",
    "研修・講演事業",
  ],
} as const;

