---
import Container from "../ui/Container.astro";
import HeroAnimation from "./HeroAnimation";
import ScrollIndicator from "../ui/ScrollIndicator";

interface Props {
  title: string;
  subtitle?: string;
  backgroundImage?: string;
  showScrollIndicator?: boolean;
  scrollTargetId?: string;
}

const {
  title,
  subtitle,
  backgroundImage = "/images/hero-bg.jpg",
  showScrollIndicator = true,
  scrollTargetId = "services",
} = Astro.props;
---

<section
  class="relative min-h-screen flex items-center justify-center overflow-hidden"
  aria-label="ヒーローセクション"
>
  {/* Background Image with Overlay */}
  <div class="absolute inset-0 z-0">
    <div
      class="absolute inset-0 bg-cover bg-center bg-no-repeat"
      style={`background-image: url('${backgroundImage}')`}
      role="img"
      aria-label="背景画像"
    >
    </div>
    {/* Gradient Overlay for contrast */}
    <div class="absolute inset-0 bg-gradient-to-b from-black/60 via-black/40 to-black/60"></div>
  </div>

  {/* Content */}
  <Container class="relative z-10 text-center py-20">
    <HeroAnimation client:visible>
      <h1 class="text-3xl sm:text-4xl md:text-5xl lg:text-6xl font-bold text-white leading-tight mb-6">
        {title}
      </h1>
      {subtitle && (
        <p class="text-lg sm:text-xl md:text-2xl text-white/90 max-w-3xl mx-auto mb-8">
          {subtitle}
        </p>
      )}
      <slot />
    </HeroAnimation>
  </Container>

  {/* Scroll Indicator */}
  {showScrollIndicator && (
    <div class="absolute bottom-8 left-1/2 -translate-x-1/2 z-10">
      <ScrollIndicator client:visible targetId={scrollTargetId} />
    </div>
  )}
</section>

---
import BaseLayout from "../layouts/BaseLayout.astro";
import Header from "../components/common/Header.astro";
import Footer from "../components/common/Footer.astro";
import Hero from "../components/sections/Hero.astro";
import ServiceCards from "../components/sections/ServiceCards.astro";
import CTASection from "../components/sections/CTASection.astro";
import Button from "../components/ui/Button.astro";
import { SITE_CONFIG } from "../lib/constants";
---

<BaseLayout
  title={`${SITE_CONFIG.name} | 仕事と介護の両立支援`}
  description={SITE_CONFIG.description}
>
  <Header transparent />

  {/* Hero Section */}
  <Hero
    title="仕事と介護の両立を、あなたのそばで支えます"
    subtitle="産業ケアマネージャーとして、企業と従業員の両方をサポート。介護離職を防ぎ、安心して働き続けられる環境づくりをお手伝いします。"
    showScrollIndicator={true}
    scrollTargetId="services"
  >
    <div class="flex flex-col sm:flex-row gap-4 justify-center mt-8">
      <Button href="/contact" size="lg" variant="primary">
        無料相談する
      </Button>
      <Button href="/services" size="lg" variant="outline" class="border-white text-white hover:bg-white/10">
        サービスを見る
      </Button>
    </div>
  </Hero>

  {/* Services Section */}
  <ServiceCards />

  {/* CTA Section */}
  <CTASection
    heading="まずはお気軽にご相談ください"
    description="介護に関するお悩みや、サービスについてのご質問など、LINEでお気軽にお問い合わせください。専門スタッフが丁寧にお答えします。"
  />

  <Footer />
</BaseLayout>

