---
import Container from "../ui/Container.astro";
import HeroAnimation from "./HeroAnimation";
import ScrollIndicator from "../ui/ScrollIndicator";

interface Props {
  title: string;
  subtitle?: string;
  backgroundImage?: string;
  showScrollIndicator?: boolean;
  scrollTargetId?: string;
}

const {
  title,
  subtitle,
  backgroundImage = "/images/hero-bg.jpg",
  showScrollIndicator = true,
  scrollTargetId = "services",
} = Astro.props;

// Convert \n to <br> for HTML rendering
const formattedTitle = title.replace(/\n/g, "<br>");
const formattedSubtitle = subtitle?.replace(/\n/g, "<br>");
---

<section
  class="relative min-h-screen flex items-center justify-center overflow-hidden"
  aria-label="ヒーローセクション"
>
  {/* Background Image with Overlay */}
  <div class="absolute inset-0 z-0">
    <div
      class="absolute inset-0 bg-cover bg-center bg-no-repeat"
      style={`background-image: url('${backgroundImage}')`}
      role="img"
      aria-label="背景画像"
    >
    </div>
    {/* Gradient Overlay for contrast */}
    <div class="absolute inset-0 bg-gradient-to-b from-black/60 via-black/40 to-black/60"></div>
  </div>

  {/* Content */}
  <Container class="relative z-10 text-center py-20">
    <HeroAnimation client:visible>
      <h1 class="text-3xl sm:text-4xl md:text-5xl lg:text-6xl font-bold text-white leading-tight mb-6" set:html={formattedTitle} />
      {formattedSubtitle && (
        <p class="text-lg sm:text-xl md:text-2xl text-white/90 max-w-3xl mx-auto mb-8" set:html={formattedSubtitle} />
      )}
      <slot />
    </HeroAnimation>
  </Container>

  {/* Scroll Indicator */}
  {showScrollIndicator && (
    <div class="absolute bottom-8 left-1/2 -translate-x-1/2 z-10">
      <ScrollIndicator client:visible targetId={scrollTargetId} />
    </div>
  )}
</section>

